const formEditar=document.querySelector("#form-editar");const nome=document.querySelector("#nome");const email=document.querySelector("#email");const senha=document.querySelector("#senha");const formDeletar=document.querySelector("#form-deletar");const confirmacao=document.querySelector("#confirmacao");formEditar.addEventListener("submit",(e)=>{e.preventDefault();const retorno=validarDadosUsuario(nome,email,senha);if(retorno.estadoErro&&retorno.msgErro&&retorno.campoErro){alternarDialogo(!0,retorno.msgErro);limparCampo(retorno.campoErro);return}
e.currentTarget.submit()});formDeletar.addEventListener("submit",(e)=>{e.preventDefault();const valConfirmacao=limparVal(confirmacao.value);if(!validarCampoObrigatorio(confirmacao,valConfirmacao,13)||valConfirmacao!=="deletar conta"){alternarDialogo(!0,"Confirmação incorreta. Por favor, tente novamente.");limparCampo(confirmacao);return}
e.currentTarget.submit()})